/**
 * Shape consumed by the Attachments family.
 *
 * Mirrors the AI SDK's FileUIPart surface but without depending on the
 * `ai` package. Consumers can pass FileUIPart directly (structurally
 * compatible) or use {@link toAttachmentData} when starting from a
 * native File.
 */
export interface AttachmentData {
  /** Stable identifier — required for tracking in *ngFor / @for */
  id: string;
  /** Filename or display label. Falls back to mediaType-derived label. */
  filename?: string;
  /** MIME type — used to pick the preview surface (image/video/audio/document/source/unknown). */
  mediaType?: string;
  /** Already-uploaded URL — used as <img>/<video> src in the preview. */
  url?: string;
  /** Native File object — used to derive a blob URL preview client-side. */
  file?: File;
  /** Byte size — when omitted, derived from `file.size` if present. */
  size?: number;
}

export type AttachmentVariant = 'grid' | 'inline' | 'list';

export type AttachmentMediaCategory =
  | 'image'
  | 'video'
  | 'audio'
  | 'document'
  | 'source'
  | 'unknown';

import {
  AttachmentData,
  AttachmentMediaCategory,
} from './attachment.types';

let idCounter = 0;
function nextId(): string {
  idCounter += 1;
  return `attachment-${Date.now().toString(36)}-${idCounter}`;
}

/**
 * Convert a native File into an AttachmentData shape that the components
 * consume. Generates a stable id if you don't provide one.
 */
export function toAttachmentData(
  file: File,
  overrides?: Partial<AttachmentData>,
): AttachmentData {
  return {
    id: overrides?.id ?? nextId(),
    filename: overrides?.filename ?? file.name,
    mediaType: overrides?.mediaType ?? file.type,
    size: overrides?.size ?? file.size,
    file,
    ...overrides,
  };
}

/**
 * Classify an attachment into a coarse media category — drives the
 * preview surface (image vs video vs audio vs generic document icon).
 */
export function getMediaCategory(
  data: Pick<AttachmentData, 'mediaType'>,
): AttachmentMediaCategory {
  const mime = data.mediaType?.toLowerCase() ?? '';
  if (mime.startsWith('image/')) return 'image';
  if (mime.startsWith('video/')) return 'video';
  if (mime.startsWith('audio/')) return 'audio';
  if (
    mime === 'application/pdf' ||
    mime.startsWith('text/') ||
    mime.includes('document') ||
    mime.includes('spreadsheet') ||
    mime.includes('presentation')
  ) {
    return 'document';
  }
  if (mime.startsWith('text/uri-list') || mime === 'application/url') {
    return 'source';
  }
  return 'unknown';
}

/**
 * Pick the best human-readable label for an attachment. Filename wins;
 * fallback hierarchy lets even a typeless blob show something useful.
 */
export function getAttachmentLabel(
  data: Pick<AttachmentData, 'filename' | 'mediaType'>,
): string {
  if (data.filename) return data.filename;
  const category = getMediaCategory(data);
  switch (category) {
    case 'image':
      return 'Image';
    case 'video':
      return 'Video';
    case 'audio':
      return 'Audio';
    case 'document':
      return 'Document';
    case 'source':
      return 'Source';
    default:
      return 'Attachment';
  }
}

/** Format byte count as a short string like "240 KB" or "12.4 MB". */
export function formatFileSize(bytes: number | undefined): string {
  if (bytes === undefined || bytes < 0) return '';
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';

/**
 * Empty-state placeholder. Render inside an {@link AttachmentList}
 * (typically gated by `@if (items.length === 0)`) to communicate
 * "no files yet" — useful in upload-first UIs.
 */
@Component({
  selector: 'attachment-empty',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <svg
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      stroke-width="1.5"
      stroke-linecap="round"
      stroke-linejoin="round"
      aria-hidden="true"
      class="size-6 opacity-60"
    >
      <path d="m21.44 11.05-9.19 9.19a6 6 0 0 1-8.49-8.49l8.57-8.57A4 4 0 1 1 17.93 8.8l-8.59 8.57a2 2 0 0 1-2.83-2.83l8.49-8.48" />
    </svg>
    <ng-content>
      <p class="text-sm">No attachments yet.</p>
    </ng-content>
  `,
  host: {
    class:
      'flex w-full flex-col items-center justify-center gap-2 rounded-md border border-dashed border-border bg-muted/30 px-4 py-6 text-center text-muted-foreground',
  },
})
export class AttachmentEmpty {}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { AttachmentItem } from './attachment-item';
import { formatFileSize } from './attachment.utils';

/**
 * Filename + optional secondary line (media type or size). Auto-truncates
 * long names with ellipsis. Tooltip exposes the full filename.
 *
 * Host display adapts to the parent variant — in row-flex parents
 * (`inline`, `list`) it claims remaining space; in column-flex (`grid`)
 * it spans full width.
 */
@Component({
  selector: 'attachment-info',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <span class="truncate text-sm leading-tight text-foreground" [attr.title]="label()">
      {{ label() }}
    </span>
    @if (secondary(); as line) {
      <span class="truncate text-xs leading-tight text-muted-foreground">{{ line }}</span>
    }
  `,
  host: {
    '[class]': 'hostClass()',
  },
})
export class AttachmentInfo {
  protected readonly parent = inject(AttachmentItem);

  readonly showMediaType = input<boolean>(false);
  readonly showSize = input<boolean>(true);

  protected readonly label = computed(() => this.parent.label());

  protected readonly hostClass = computed(() => {
    const variant = this.parent.resolvedVariant();
    const base = 'flex min-w-0 flex-col gap-0.5';
    if (variant === 'grid') {
      // Column-flex parent — span the card width, don't stretch vertically.
      return `${base} w-full pt-1`;
    }
    // Row-flex parent — fill remaining horizontal space.
    return `${base} flex-1`;
  });

  protected readonly secondary = computed<string | null>(() => {
    const data = this.parent.data();
    const parts: string[] = [];
    if (this.showMediaType() && data.mediaType) {
      parts.push(data.mediaType);
    }
    if (this.showSize() && data.size !== undefined) {
      parts.push(formatFileSize(data.size));
    }
    if (parts.length === 0) return null;
    return parts.join(' · ');
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  inject,
  input,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';

import { AttachmentList } from './attachment-list';
import {
  AttachmentData,
  AttachmentMediaCategory,
} from './attachment.types';
import {
  getAttachmentLabel,
  getMediaCategory,
} from './attachment.utils';

const itemVariants = cva(
  'group/attachment relative rounded-md border border-border bg-card text-card-foreground transition-colors motion-safe:animate-[gremorie-fade-in_120ms_ease-out]',
  {
    variants: {
      variant: {
        // Column-flex card with thumbnail on top, info below.
        grid: 'flex w-[220px] flex-col items-stretch gap-2 p-2',
        // Compact badge — row-flex, small icon + text + remove.
        inline: 'inline-flex h-9 max-w-[220px] items-center gap-1.5 px-2 py-1',
        // Wide row — square thumbnail, info, remove.
        list: 'flex w-full items-center gap-3 p-2',
      },
      errored: {
        true: 'border-destructive',
        false: '',
      },
    },
    defaultVariants: {
      variant: 'grid',
      errored: false,
    },
  },
);

/**
 * Individual attachment wrapper. Provides its data + state to children
 * (preview, info, remove, etc) via DI so they can be composed in any
 * order without prop-drilling.
 */
@Component({
  selector: 'attachment-item',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    role: 'listitem',
    '[attr.data-id]': 'data().id',
    '[attr.data-media-category]': 'mediaCategory()',
    '[attr.data-loading]': 'loading() ? "" : null',
    '[attr.data-error]': 'errored() ? "" : null',
    '[class]': 'hostClass()',
  },
})
export class AttachmentItem {
  /**
   * Parent list is optional — the item still works standalone outside
   * of an AttachmentList (read variant directly from input).
   */
  private readonly list = inject(AttachmentList, { optional: true });

  readonly data = input.required<AttachmentData>();
  readonly loading = input<boolean>(false);
  readonly errored = input<boolean>(false);
  readonly variant = input<'grid' | 'inline' | 'list' | undefined>(undefined);

  readonly removed = output<AttachmentData>();

  private readonly previewUrl = signal<string | null>(null);

  readonly resolvedVariant = computed(
    () => this.variant() ?? this.list?.variant() ?? 'grid',
  );

  readonly mediaCategory = computed<AttachmentMediaCategory>(() =>
    getMediaCategory(this.data()),
  );

  readonly label = computed(() => getAttachmentLabel(this.data()));

  protected readonly hostClass = computed(() =>
    itemVariants({
      variant: this.resolvedVariant(),
      errored: this.errored(),
    }),
  );

  constructor() {
    effect((onCleanup) => {
      const current = this.data();
      // Only generate blob URL when we have a File and no explicit URL.
      if (current.url) {
        this.previewUrl.set(current.url);
        return;
      }
      if (current.file && getMediaCategory(current) === 'image') {
        const url = URL.createObjectURL(current.file);
        this.previewUrl.set(url);
        onCleanup(() => URL.revokeObjectURL(url));
        return;
      }
      this.previewUrl.set(null);
    });
  }

  /** Called by `<attachment-remove>` via DI. */
  emitRemove(): void {
    this.removed.emit(this.data());
  }

  /** Current preview URL — resolved from `data.url` or generated from `data.file`. */
  getPreviewUrl(): string | null {
    return this.previewUrl();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cva, type VariantProps } from 'class-variance-authority';

import { AttachmentVariant } from './attachment.types';

/**
 * Layout for the attachment list.
 *
 * - **grid** — wraps cards, best for message bubbles or rich preview.
 * - **inline** — compact badge row, best for input toolbars.
 * - **list** — vertical stack with full metadata, best for upload UIs.
 */
const listVariants = cva('flex w-full', {
  variants: {
    variant: {
      grid: 'flex-wrap items-start gap-3',
      inline: 'flex-wrap items-center gap-2',
      list: 'flex-col gap-2',
    },
  },
  defaultVariants: {
    variant: 'grid',
  },
});

export type AttachmentListVariantProps = VariantProps<typeof listVariants>;

@Component({
  selector: 'attachment-list',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    role: 'list',
    '[attr.aria-label]': 'ariaLabel()',
    '[attr.data-variant]': 'variant()',
    '[class]': 'hostClass()',
  },
})
export class AttachmentList {
  readonly variant = input<AttachmentVariant>('grid');
  readonly ariaLabel = input<string>('Attachments');

  protected readonly hostClass = computed(() =>
    listVariants({ variant: this.variant() }),
  );
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { AttachmentItem } from './attachment-item';

/**
 * Filename only — finer-grained than {@link AttachmentInfo}. Use when
 * you want full control over layout (e.g. wrap with a custom badge).
 *
 * Host display adapts to the parent variant: `flex-1` in row-flex
 * (`inline`/`list`), `w-full` in column-flex (`grid`).
 */
@Component({
  selector: 'attachment-name',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `{{ label() }}`,
  host: {
    '[class]': 'hostClass()',
    '[attr.title]': 'label()',
  },
})
export class AttachmentName {
  protected readonly parent = inject(AttachmentItem);

  protected readonly label = computed(() => this.parent.label());

  protected readonly hostClass = computed(() => {
    const variant = this.parent.resolvedVariant();
    const base = 'block min-w-0 truncate text-sm text-foreground';
    return variant === 'grid' ? `${base} w-full` : `${base} flex-1`;
  });
}

import { NgTemplateOutlet } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  TemplateRef,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';

import { AttachmentItem } from './attachment-item';
import { AttachmentMediaCategory } from './attachment.types';

const previewVariants = cva(
  'relative flex shrink-0 items-center justify-center overflow-hidden bg-muted text-muted-foreground',
  {
    variants: {
      variant: {
        grid: 'h-32 w-full rounded-md',
        inline: 'size-5 rounded-sm',
        list: 'size-10 rounded-md',
      },
    },
    defaultVariants: { variant: 'grid' },
  },
);

const ICON_BY_CATEGORY: Record<
  Exclude<AttachmentMediaCategory, 'image'>,
  string
> = {
  video:
    'M23 7l-7 5 7 5V7z M14 5H3a2 2 0 0 0-2 2v10a2 2 0 0 0 2 2h11a2 2 0 0 0 2-2V7a2 2 0 0 0-2-2z',
  audio:
    'M9 18V5l12-2v13 M6 18a3 3 0 1 0 3 3v-3 M18 16a3 3 0 1 0 3 3v-3',
  document:
    'M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z M14 2v6h6 M16 13H8 M16 17H8',
  source:
    'M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71 M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71',
  unknown:
    'M13 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V9z M13 2v7h7',
};

/**
 * Visual preview surface. Renders an <img> for image data when a blob
 * URL or static URL is available, otherwise a media-type icon.
 *
 * Override entirely via the optional `fallback` TemplateRef input —
 * useful when you have your own icon system (lucide / heroicons / etc).
 *
 * Classes are applied to the host so the element behaves as the styled
 * box itself (no extra wrapper layer between item and image/icon).
 */
@Component({
  selector: 'attachment-preview',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [NgTemplateOutlet],
  template: `
    @if (mediaCategory() === 'image' && imageSrc(); as src) {
      <img [src]="src" [alt]="alt()" class="size-full object-cover" />
    } @else if (fallback(); as tmpl) {
      <ng-container *ngTemplateOutlet="tmpl"></ng-container>
    } @else {
      <svg
        [class]="iconClass()"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="1.75"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
      >
        <path [attr.d]="iconPath()"></path>
      </svg>
    }
    @if (parent.loading()) {
      <span class="absolute inset-0 animate-pulse bg-muted/60"></span>
    }
    @if (parent.errored()) {
      <span class="absolute inset-x-0 bottom-0 bg-destructive py-0.5 text-center text-[10px] font-medium text-destructive-foreground">
        Error
      </span>
    }
  `,
  host: {
    '[class]': 'hostClass()',
    '[attr.data-variant]': 'parent.resolvedVariant()',
  },
})
export class AttachmentPreview {
  protected readonly parent = inject(AttachmentItem);

  readonly fallback = input<TemplateRef<unknown> | null>(null);

  protected readonly mediaCategory = computed(() =>
    this.parent.mediaCategory(),
  );

  protected readonly imageSrc = computed(() => this.parent.getPreviewUrl());

  protected readonly alt = computed(
    () => this.parent.data().filename ?? 'Attachment preview',
  );

  protected readonly hostClass = computed(() =>
    previewVariants({ variant: this.parent.resolvedVariant() }),
  );

  protected readonly iconClass = computed(() => {
    const variant = this.parent.resolvedVariant();
    return variant === 'inline' ? 'size-3.5' : 'size-5';
  });

  protected readonly iconPath = computed(() => {
    const category = this.mediaCategory();
    if (category === 'image') return '';
    return ICON_BY_CATEGORY[category];
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  ViewEncapsulation,
} from '@angular/core';

import { AttachmentItem } from './attachment-item';

/**
 * Remove button. Calls the parent {@link AttachmentItem}'s `removed`
 * output via DI — consumers can put it anywhere inside the item.
 *
 * Position-aware: absolute top-right for the `grid` variant (revealed
 * on hover), inline for `list` and `inline` variants.
 */
@Component({
  selector: 'attachment-remove',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      [class]="buttonClass()"
      [attr.aria-label]="label()"
      (click)="handleClick($event)"
    >
      <svg
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
        class="size-3.5"
      >
        <line x1="18" y1="6" x2="6" y2="18" />
        <line x1="6" y1="6" x2="18" y2="18" />
      </svg>
    </button>
  `,
  host: {
    '[class]': 'hostClass()',
  },
})
export class AttachmentRemove {
  protected readonly parent = inject(AttachmentItem);

  readonly label = input<string>('Remove attachment');

  protected readonly hostClass = computed(() => {
    const variant = this.parent.resolvedVariant();
    // For grid variant the host floats absolutely; for others it sits inline.
    if (variant === 'grid') {
      return 'absolute right-1.5 top-1.5 z-10 inline-flex';
    }
    return 'inline-flex shrink-0';
  });

  protected readonly buttonClass = computed(() => {
    const variant = this.parent.resolvedVariant();
    const base =
      'inline-flex size-6 shrink-0 items-center justify-center rounded text-muted-foreground transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring';
    if (variant === 'grid') {
      return `${base} bg-background/80 opacity-0 backdrop-blur-sm group-hover/attachment:opacity-100 focus-visible:opacity-100`;
    }
    return base;
  });

  protected handleClick(event: Event): void {
    event.stopPropagation();
    this.parent.emitRemove();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { AttachmentItem } from './attachment-item';
import { formatFileSize } from './attachment.utils';

/**
 * Formatted byte size. Hidden when the data has no `size` field.
 */
@Component({
  selector: 'attachment-size',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `@if (formatted(); as size) {{{ size }}}`,
  host: {
    class: 'text-xs text-muted-foreground',
    '[hidden]': '!formatted()',
  },
})
export class AttachmentSize {
  protected readonly parent = inject(AttachmentItem);

  protected readonly formatted = computed(() => {
    const size = this.parent.data().size;
    if (size === undefined) return null;
    return formatFileSize(size);
  });
}

import type { AttachmentData } from '../attachments/attachment.types';

export type PromptInputState =
  | 'ready'
  | 'submitted'
  | 'streaming'
  | 'error';

export type PromptInputSize = 'sm' | 'md' | 'lg';

export type PromptInputVariant = 'default' | 'ghost' | 'bordered';

export interface PromptInputSubmitEvent {
  value: string;
  attachments: readonly AttachmentData[];
  preventDefault: () => void;
}

export interface PromptInputAttachmentError {
  file: File;
  reason: 'invalid-mime' | 'too-large' | 'max-count';
  message: string;
}

export interface PromptInputModelOption {
  id: string;
  label: string;
  description?: string;
  badge?: string;
  disabled?: boolean;
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  HostListener,
  inject,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { cva } from 'class-variance-authority';
import { cn } from '@gremorie/ng-core';
import { toAttachmentData } from '../attachments/attachment.utils';
import type { AttachmentData } from '../attachments/attachment.types';

import {
  PromptInputAttachmentError,
  PromptInputSize,
  PromptInputState,
  PromptInputSubmitEvent,
  PromptInputVariant,
} from './prompt-input.types';

const containerVariants = cva(
  'relative flex w-full flex-col rounded-md transition-colors focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2 focus-within:ring-offset-background',
  {
    variants: {
      size: {
        sm: 'gap-1.5 p-2.5 text-sm',
        md: 'gap-2 p-3 text-sm',
        lg: 'gap-3 p-4 text-base',
      },
      variant: {
        default: 'border border-input bg-background',
        ghost: 'border border-transparent bg-transparent',
        bordered: 'border-2 border-input bg-background',
      },
      state: {
        ready: '',
        submitted: '',
        streaming: '',
        error: 'border-destructive focus-within:ring-destructive',
      },
    },
    defaultVariants: {
      size: 'md',
      variant: 'default',
      state: 'ready',
    },
  },
);

@Component({
  selector: 'prompt-input',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <ng-content />
    <span class="sr-only" aria-live="polite" aria-atomic="true">{{ statusAnnouncement() }}</span>
  `,
  host: {
    role: 'form',
    '[class]': 'hostClass()',
    '[attr.aria-label]': 'ariaLabel()',
    '[attr.aria-disabled]': 'disabled() ? "true" : null',
    '[attr.data-state]': 'state()',
    '[attr.data-disabled]': 'disabled() ? "" : null',
    '[attr.data-dragging]': 'isDragging() ? "" : null',
    '(keydown)': 'handleKeydown($event)',
    '(dragover)': 'handleDragOver($event)',
    '(dragenter)': 'handleDragEnter($event)',
    '(dragleave)': 'handleDragLeave($event)',
    '(drop)': 'handleDrop($event)',
  },
})
export class PromptInput {
  private readonly elementRef: ElementRef<HTMLElement> = inject(ElementRef);

  readonly value = model<string>('');
  readonly attachments = model<readonly AttachmentData[]>([]);

  readonly state = input<PromptInputState>('ready');
  readonly size = input<PromptInputSize>('md');
  readonly variant = input<PromptInputVariant>('default');
  readonly disabled = input<boolean>(false);
  readonly submitOnEnter = input<boolean>(true);
  readonly ariaLabel = input<string>('AI prompt input');

  /**
   * When `false`, file attachments are disabled (drag-drop and paste ignored).
   * Otherwise, an array of MIME patterns (`image/*`, `application/pdf`, etc.)
   * that are accepted.
   */
  readonly acceptAttachments = input<readonly string[] | false>(false);
  readonly maxAttachments = input<number>(10);
  readonly maxAttachmentSize = input<number>(10 * 1024 * 1024); // 10MB

  readonly submitted = output<PromptInputSubmitEvent>();
  readonly canceled = output<void>();
  readonly retried = output<void>();
  readonly attachmentError = output<PromptInputAttachmentError>();

  private readonly dragCounter = signal(0);

  readonly isDragging = computed(() => this.dragCounter() > 0);

  readonly attachmentsEnabled = computed(() => {
    const accept = this.acceptAttachments();
    return accept !== false && !this.disabled();
  });

  readonly statusAnnouncement = computed(() => {
    switch (this.state()) {
      case 'submitted':
        return 'Message submitted. Waiting for response.';
      case 'streaming':
        return 'AI is responding.';
      case 'error':
        return 'Submission failed. Press the button to retry.';
      default:
        return '';
    }
  });

  readonly hostClass = computed(() =>
    cn(
      containerVariants({
        size: this.size(),
        variant: this.variant(),
        state: this.state(),
      }),
      this.disabled() && 'pointer-events-none opacity-50',
      this.isDragging() && 'ring-2 ring-ring ring-offset-2',
    ),
  );

  handleKeydown(event: KeyboardEvent): void {
    if (this.disabled()) {
      return;
    }

    const isEnter = event.key === 'Enter';
    const isMod = event.metaKey || event.ctrlKey;

    if (isEnter && isMod) {
      event.preventDefault();
      this.submit();
      return;
    }

    if (isEnter && !event.shiftKey && this.submitOnEnter()) {
      event.preventDefault();
      this.submit();
      return;
    }

    if (event.key === 'Escape') {
      event.preventDefault();
      this.handleEscape();
    }
  }

  @HostListener('document:keydown', ['$event'])
  handleGlobalKeydown(event: KeyboardEvent): void {
    const isMod = event.metaKey || event.ctrlKey;
    if (isMod && event.key.toLowerCase() === 'k') {
      event.preventDefault();
      this.focusTextarea();
    }
  }

  @HostListener('paste', ['$event'])
  handlePaste(event: ClipboardEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    const items = event.clipboardData?.items;
    if (!items) {
      return;
    }
    const files: File[] = [];
    for (let i = 0; i < items.length; i++) {
      const item = items[i];
      if (item.kind === 'file') {
        const file = item.getAsFile();
        if (file) {
          files.push(file);
        }
      }
    }
    if (files.length > 0) {
      event.preventDefault();
      this.addFiles(files);
    }
  }

  handleDragOver(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    if (event.dataTransfer) {
      event.dataTransfer.dropEffect = 'copy';
    }
  }

  handleDragEnter(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.update((n) => n + 1);
  }

  handleDragLeave(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.update((n) => Math.max(0, n - 1));
  }

  handleDrop(event: DragEvent): void {
    if (!this.attachmentsEnabled()) {
      return;
    }
    event.preventDefault();
    this.dragCounter.set(0);
    const files = event.dataTransfer?.files;
    if (files && files.length > 0) {
      this.addFiles(Array.from(files));
    }
  }

  submit(): void {
    if (this.disabled()) {
      return;
    }

    const currentState = this.state();

    if (currentState === 'streaming') {
      this.canceled.emit();
      return;
    }

    if (currentState === 'error') {
      this.retried.emit();
      return;
    }

    const event: PromptInputSubmitEvent = {
      value: this.value(),
      attachments: this.attachments(),
      preventDefault: () => {
        /* Consumer can short-circuit clearing/UI by calling this. */
      },
    };
    this.submitted.emit(event);
  }

  clear(): void {
    this.value.set('');
    this.attachments.set([]);
  }

  focusTextarea(): void {
    const textarea = this.elementRef.nativeElement.querySelector('textarea');
    textarea?.focus();
  }

  addFiles(files: readonly File[]): void {
    for (const file of files) {
      const error = this.validateFile(file);
      if (error) {
        this.attachmentError.emit(error);
        continue;
      }
      this.attachments.update((prev) => [...prev, toAttachmentData(file)]);
    }
  }

  /**
   * Remove an attachment by reference, by id, or by underlying File. The
   * three signatures let consumers match whatever they have in hand
   * (full object, just the id, or the original File from drag-drop).
   */
  removeAttachment(target: AttachmentData | string | File): void {
    this.attachments.update((prev) =>
      prev.filter((item) => {
        if (typeof target === 'string') return item.id !== target;
        if (target instanceof File) return item.file !== target;
        return item.id !== target.id;
      }),
    );
  }

  private validateFile(file: File): PromptInputAttachmentError | null {
    const accept = this.acceptAttachments();
    if (accept !== false && accept.length > 0) {
      const isAccepted = accept.some((pattern) => {
        if (pattern.endsWith('/*')) {
          return file.type.startsWith(pattern.slice(0, -1));
        }
        return file.type === pattern;
      });
      if (!isAccepted) {
        return {
          file,
          reason: 'invalid-mime',
          message: `MIME type "${file.type}" not accepted`,
        };
      }
    }

    if (file.size > this.maxAttachmentSize()) {
      const mb = (this.maxAttachmentSize() / (1024 * 1024)).toFixed(1);
      return {
        file,
        reason: 'too-large',
        message: `File "${file.name}" exceeds maximum size of ${mb} MB`,
      };
    }

    if (this.attachments().length >= this.maxAttachments()) {
      return {
        file,
        reason: 'max-count',
        message: `Maximum of ${this.maxAttachments()} attachments reached`,
      };
    }

    return null;
  }

  private handleEscape(): void {
    const currentState = this.state();
    if (currentState === 'streaming') {
      this.canceled.emit();
      return;
    }
    this.clear();
  }
}

